+
+/* ============================================
+   Animations
+   ============================================ */
+
+@keyframes gradient-shift {
+  0%, 100% {
+    background-position: 0% 50%;
+  }
+  50% {
+    background-position: 100% 50%;
+  }
+}
+
+@keyframes float {
+  0%, 100% {
+    transform: translateY(0px);
+  }
+  50% {
+    transform: translateY(-10px);
+  }
+}
+
+@keyframes pulse-glow {
+  0%, 100% {
+    opacity: 0.4;
+    transform: scale(1);
+  }
+  50% {
+    opacity: 0.8;
+    transform: scale(1.05);
+  }
+}
+
+@keyframes shimmer {
+  0% {
+    background-position: -200% 0;
+  }
+  100% {
+    background-position: 200% 0;
+  }
+}
+
+@keyframes typing {
+  from {
+    width: 0;
+  }
+  to {
+    width: 100%;
+  }
+}
+
+@keyframes blink {
+  0%, 50% {
+    opacity: 1;
+  }
+  51%, 100% {
+    opacity: 0;
+  }
+}
+
+@keyframes slide-up {
+  from {
+    opacity: 0;
+    transform: translateY(20px);
+  }
+  to {
+    opacity: 1;
+    transform: translateY(0);
+  }
+}
+
+@keyframes slide-in-left {
+  from {
+    opacity: 0;
+    transform: translateX(-20px);
+  }
+  to {
+    opacity: 1;
+    transform: translateX(0);
+  }
+}
+
+@keyframes scale-in {
+  from {
+    opacity: 0;
+    transform: scale(0.95);
+  }
+  to {
+    opacity: 1;
+    transform: scale(1);
+  }
+}
+
+@keyframes glow-pulse {
+  0%, 100% {
+    box-shadow: 0 0 20px oklch(0.75 0.18 195 / 0.3),
+                0 0 40px oklch(0.75 0.18 195 / 0.1);
+  }
+  50% {
+    box-shadow: 0 0 30px oklch(0.75 0.18 195 / 0.5),
+                0 0 60px oklch(0.75 0.18 195 / 0.2);
+  }
+}
+
+@keyframes border-glow {
+  0%, 100% {
+    border-color: oklch(0.75 0.18 195 / 0.3);
+  }
+  50% {
+    border-color: oklch(0.75 0.18 195 / 0.6);
+  }
+}
+
+@keyframes confetti-fall {
+  0% {
+    transform: translateY(-100vh) rotate(0deg);
+    opacity: 1;
+  }
+  100% {
+    transform: translateY(100vh) rotate(720deg);
+    opacity: 0;
+  }
+}
+
+@keyframes orbit {
+  from {
+    transform: rotate(0deg) translateX(100px) rotate(0deg);
+  }
+  to {
+    transform: rotate(360deg) translateX(100px) rotate(-360deg);
+  }
+}
+
+/* Animation utility classes */
+.animate-gradient-shift {
+  animation: gradient-shift 8s ease infinite;
+  background-size: 200% 200%;
+}
+
+.animate-float {
+  animation: float 6s ease-in-out infinite;
+}
+
+.animate-pulse-glow {
+  animation: pulse-glow 3s ease-in-out infinite;
+}
+
+.animate-shimmer {
+  animation: shimmer 2s linear infinite;
+  background-size: 200% 100%;
+}
+
+.animate-slide-up {
+  animation: slide-up 0.5s ease-out forwards;
+}
+
+.animate-slide-in-left {
+  animation: slide-in-left 0.5s ease-out forwards;
+}
+
+.animate-scale-in {
+  animation: scale-in 0.3s ease-out forwards;
+}
+
+.animate-glow-pulse {
+  animation: glow-pulse 2s ease-in-out infinite;
+}
+
+.animate-border-glow {
+  animation: border-glow 2s ease-in-out infinite;
+}
+
+/* Staggered animation delays */
+.stagger-1 { animation-delay: 0.1s; }
+.stagger-2 { animation-delay: 0.2s; }
+.stagger-3 { animation-delay: 0.3s; }
+.stagger-4 { animation-delay: 0.4s; }
+.stagger-5 { animation-delay: 0.5s; }
+.stagger-6 { animation-delay: 0.6s; }
+
+/* ============================================
+   Background Effects
+   ============================================ */
+
+.bg-grid-pattern {
+  background-image:
+    linear-gradient(oklch(0.25 0.02 260 / 0.3) 1px, transparent 1px),
+    linear-gradient(90deg, oklch(0.25 0.02 260 / 0.3) 1px, transparent 1px);
+  background-size: 40px 40px;
+}
+
+.bg-noise {
+  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 400 400' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E");
+  opacity: 0.03;
+}
+
+.bg-gradient-radial {
+  background: radial-gradient(ellipse at center, var(--tw-gradient-from), var(--tw-gradient-to));
+}
+
+.bg-gradient-cosmic {
+  background:
+    radial-gradient(ellipse at 20% 30%, oklch(0.75 0.18 195 / 0.15) 0%, transparent 50%),
+    radial-gradient(ellipse at 80% 70%, oklch(0.7 0.2 330 / 0.1) 0%, transparent 50%),
+    radial-gradient(ellipse at 50% 50%, oklch(0.65 0.18 290 / 0.08) 0%, transparent 60%);
+}
+
+.bg-gradient-hero {
+  background:
+    radial-gradient(ellipse at 30% 20%, oklch(0.75 0.18 195 / 0.2) 0%, transparent 40%),
+    radial-gradient(ellipse at 70% 80%, oklch(0.7 0.2 330 / 0.15) 0%, transparent 40%),
+    radial-gradient(ellipse at 90% 30%, oklch(0.78 0.16 75 / 0.1) 0%, transparent 30%),
+    linear-gradient(180deg, oklch(0.11 0.015 260) 0%, oklch(0.09 0.02 270) 100%);
+}
+
+/* ============================================
+   Component Utilities
+   ============================================ */
+
+/* Glass morphism effect */
+.glass {
+  background: oklch(0.14 0.02 260 / 0.8);
+  backdrop-filter: blur(12px);
+  -webkit-backdrop-filter: blur(12px);
+  border: 1px solid oklch(0.3 0.02 260 / 0.3);
+}
+
+.glass-subtle {
+  background: oklch(0.14 0.02 260 / 0.6);
+  backdrop-filter: blur(8px);
+  -webkit-backdrop-filter: blur(8px);
+}
+
+/* Glow effects */
+.glow-cyan {
+  box-shadow: 0 0 20px oklch(0.75 0.18 195 / 0.3);
+}
+
+.glow-amber {
+  box-shadow: 0 0 20px oklch(0.78 0.16 75 / 0.3);
+}
+
+.glow-magenta {
+  box-shadow: 0 0 20px oklch(0.7 0.2 330 / 0.3);
+}
+
+/* Text gradients */
+.text-gradient-cyan {
+  background: linear-gradient(135deg, oklch(0.75 0.18 195), oklch(0.72 0.16 165));
+  -webkit-background-clip: text;
+  -webkit-text-fill-color: transparent;
+  background-clip: text;
+}
+
+.text-gradient-warm {
+  background: linear-gradient(135deg, oklch(0.78 0.16 75), oklch(0.7 0.2 330));
+  -webkit-background-clip: text;
+  -webkit-text-fill-color: transparent;
+  background-clip: text;
+}
+
+.text-gradient-cosmic {
+  background: linear-gradient(135deg, oklch(0.75 0.18 195), oklch(0.7 0.2 330), oklch(0.78 0.16 75));
+  -webkit-background-clip: text;
+  -webkit-text-fill-color: transparent;
+  background-clip: text;
+}
+
+/* Terminal styling */
+.terminal-window {
+  background: oklch(0.08 0.015 260);
+  border: 1px solid oklch(0.25 0.02 260);
+  border-radius: 12px;
+  overflow: hidden;
+}
+
+.terminal-header {
+  background: oklch(0.12 0.02 260);
+  padding: 12px 16px;
+  display: flex;
+  align-items: center;
+  gap: 8px;
+  border-bottom: 1px solid oklch(0.2 0.02 260);
+}
+
+.terminal-dot {
+  width: 12px;
+  height: 12px;
+  border-radius: 50%;
+}
+
+.terminal-dot-red { background: oklch(0.65 0.22 25); }
+.terminal-dot-yellow { background: oklch(0.78 0.16 75); }
+.terminal-dot-green { background: oklch(0.72 0.19 145); }
+
+.terminal-content {
+  padding: 20px;
+  font-family: var(--font-jetbrains), monospace;
+  font-size: 14px;
+  line-height: 1.7;
+}
+
+.terminal-line {
+  display: flex;
+  align-items: flex-start;
+  gap: 8px;
+}
+
+.terminal-prompt {
+  color: oklch(0.72 0.19 145);
+  user-select: none;
+}
+
+.terminal-command {
+  color: oklch(0.9 0.01 260);
+}
+
+.terminal-output {
+  color: oklch(0.6 0.02 260);
+  padding-left: 20px;
+}
+
+.terminal-cursor {
+  display: inline-block;
+  width: 8px;
+  height: 18px;
+  background: oklch(0.75 0.18 195);
+  animation: blink 1s step-end infinite;
+  margin-left: 2px;
+  vertical-align: middle;
+}
+
+/* Syntax highlighting for terminal */
+.syntax-string { color: oklch(0.78 0.16 75); }
+.syntax-number { color: oklch(0.7 0.2 330); }
+.syntax-keyword { color: oklch(0.75 0.18 195); }
+.syntax-comment { color: oklch(0.5 0.02 260); }
+.syntax-function { color: oklch(0.72 0.16 145); }
+
+/* Card hover effects */
+.card-hover {
+  transition: all 0.3s ease;
+}
+
+.card-hover:hover {
+  transform: translateY(-4px);
+  box-shadow:
+    0 20px 40px oklch(0 0 0 / 0.3),
+    0 0 0 1px oklch(0.75 0.18 195 / 0.2);
+}
+
+/* Button styles */
+.btn-glow {
+  position: relative;
+  overflow: hidden;
+}
+
+.btn-glow::before {
+  content: '';
+  position: absolute;
+  inset: -2px;
+  background: linear-gradient(135deg, oklch(0.75 0.18 195), oklch(0.7 0.2 330));
+  border-radius: inherit;
+  z-index: -1;
+  opacity: 0;
+  transition: opacity 0.3s ease;
+}
+
+.btn-glow:hover::before {
+  opacity: 1;
+}
+
+.btn-glow::after {
+  content: '';
+  position: absolute;
+  inset: 1px;
+  background: inherit;
+  border-radius: inherit;
+  z-index: -1;
+}
+
+/* ============================================
+   Typography
+   ============================================ */
+
+.font-display {
+  font-family: var(--font-jetbrains), monospace;
+  font-weight: 700;
+  letter-spacing: -0.02em;
+}
+
+.font-mono {
+  font-family: var(--font-jetbrains), monospace;
+}
+
+/* Fancy underline effect */
+.fancy-underline {
+  position: relative;
+  display: inline-block;
+}
+
+.fancy-underline::after {
+  content: '';
+  position: absolute;
+  bottom: -2px;
+  left: 0;
+  width: 100%;
+  height: 2px;
+  background: linear-gradient(90deg, oklch(0.75 0.18 195), oklch(0.7 0.2 330));
+  transform: scaleX(0);
+  transform-origin: right;
+  transition: transform 0.3s ease;
+}
+
+.fancy-underline:hover::after {
+  transform: scaleX(1);
+  transform-origin: left;
+}
+
+/* ============================================
+   Page Transitions
+   ============================================ */
+
+.page-enter {
+  opacity: 0;
+  transform: translateY(10px);
+}
+
+.page-enter-active {
+  opacity: 1;
+  transform: translateY(0);
+  transition: opacity 0.3s ease, transform 0.3s ease;
+}
+
+.page-exit {
+  opacity: 1;
+}
+
+.page-exit-active {
+  opacity: 0;
+  transition: opacity 0.2s ease;
+}
+
+/* ============================================
+   Mobile Optimizations
+   ============================================ */
+
+@media (max-width: 768px) {
+  .terminal-content {
+    font-size: 12px;
+    padding: 16px;
+  }
+
+  .bg-gradient-hero {
+    background:
+      radial-gradient(ellipse at 50% 20%, oklch(0.75 0.18 195 / 0.2) 0%, transparent 50%),
+      linear-gradient(180deg, oklch(0.11 0.015 260) 0%, oklch(0.09 0.02 270) 100%);
+  }
+}
+
+/* Touch-friendly tap highlights */
+@media (hover: none) {
+  .card-hover:active {
+    transform: scale(0.98);
+  }
+}
+
+/* ============================================
+   Accessibility
+   ============================================ */
+
+@media (prefers-reduced-motion: reduce) {
+  *,
+  *::before,
+  *::after {
+    animation-duration: 0.01ms !important;
+    animation-iteration-count: 1 !important;
+    transition-duration: 0.01ms !important;
+  }
+}
+
+/* Focus visible styles */
+:focus-visible {
+  outline: 2px solid oklch(0.75 0.18 195);
+  outline-offset: 2px;
+}
+
+/* High contrast mode support */
+@media (prefers-contrast: high) {
+  :root {
+    --border: oklch(0.5 0.02 260);
+    --muted-foreground: oklch(0.75 0.02 260);
   }
 }

