+// Confetti particle component
+function ConfettiParticle({ delay, left }: { delay: number; left: number }) {
+  const colors = [
+    "oklch(0.75 0.18 195)", // cyan
+    "oklch(0.78 0.16 75)",  // amber
+    "oklch(0.7 0.2 330)",   // magenta
+    "oklch(0.72 0.19 145)", // green
